export const MLRO_RED_FLAG_BUCKET_LABELS: Record<RedFlagBucket, string> = {
  transaction: "Transaction-level",
  customer: "Customer-level",
  supplier: "Supplier / counterparty",
  geographic: "Geographic",
  product: "Product / instrument",
  behavioral: "Behavioral / pattern",
  regulatory: "Regulatory / enforcement",
};

export function searchRedFlags(query: string): MlroRedFlag[] {
  const q = query.trim().toLowerCase();
  if (!q) return [];
  const tokens = q.split(/\s+/).filter(Boolean);
  return MLRO_RED_FLAGS_TAXONOMY.filter((rf) => {
    const hay = (rf.label + ' ' + rf.id + ' ' + rf.bucket).toLowerCase();
    return tokens.every((t) => hay.includes(t));
  });
}
